        "type": "object",
        "required": [
          "id",
          "plantId",
          "plantName",
          "type",
          "due",
          "done",
          "status"
        ],
        "properties": {
          "id": {
            "type": "string",
            "description": "stable task id, e.g. \"task-03\""
          },
          "plantId": {
            "type": "string",
            "description": "id of the plant this task belongs to"
          },
          "plantName": {
            "type": "string",
            "minLength": 1,
            "description": "denormalised for display — the row renders without fetching the plant"
          },
          "type": {
            "type": "string",
            "enum": [
              "water",
              "fertilise",
              "repot",
              "inspect"
            ]
          },
          "due": {
            "type": "string",
            "format": "date"
          },
          "done": {
            "type": "boolean",
            "description": "already logged in the scenario's history; done tasks carry status \"ok\" and stay out of the Today list"
          },
          "status": {
            "type": "string",
            "enum": [
              "ok",
              "due",
              "overdue"
            ],
            "description": "derived from due vs the scenario's fixed fictional today"
          }
        },
        "additionalProperties": false
      }
    },
    "demo-notice": {
      "class": "vd-demo-notice",
